import React, { useEffect, useRef, useState } from 'react';
import '../styles/GameCanvas.css';
import { AWS_ICON_CATEGORIES, SERVICE_MAPPINGS } from '../services/IconResolver';

// S3 Paths
const S3_BUCKET_URL = 'https://hackthon-backend-files-ep-2024.s3.amazonaws.com';
const ICONS_BASE_PATH = '/amazon-icons-set/Architecture-Service-Icons_06072024';
const S3_ROCKET_PATH = `${S3_BUCKET_URL}/games/rocket`;
const DEFAULT_ROCKET = `${S3_ROCKET_PATH}/rocket1.png`;
const FIREBALL_PATH = `${S3_BUCKET_URL}/games/bullet/fireball.png`;

const GameCanvas = () => {
  const [timeLeft, setTimeLeft] = useState(60);
  const [score, setScore] = useState(0);
  const [currentInstructionIndex, setCurrentInstructionIndex] = useState(0);
  const [selectedRocket, setSelectedRocket] = useState(localStorage.getItem('selectedRocket') || null);
  const [playerName, setPlayerName] = useState(localStorage.getItem('playerName') || '');
  const [gameStarted, setGameStarted] = useState(false);
  const [gameOver, setGameOver] = useState(false);

  const canvasRef = useRef(null);
  const iconsRef = useRef([]);
  const bulletsRef = useRef([]);

  const rocketImage = useRef(new Image());
  const fireballImage = new Image();
  fireballImage.src = FIREBALL_PATH;

  useEffect(() => {
    rocketImage.current.src = selectedRocket;
  }, [selectedRocket]);

  // Function to generate a new category mission
  const NewCategoryMission = () => {
    if (!gameStarted) return;

    console.log("Starting new category mission...");
    iconsRef.current = [];
    const positions = [];

    const getRandomCategories = () => {
      const categories = Object.keys(AWS_ICON_CATEGORIES);
      return [...categories].sort(() => 0.5 - Math.random()).slice(0, 2);
    };

    const newInstructions = getRandomCategories().map(category => ({
      text: `Shoot the ${category.replace('_', ' ')} icons!`,
      category: AWS_ICON_CATEGORIES[category],
      displayName: category
    }));

    setCurrentInstructionIndex(0);
    const currentCategory = newInstructions[0].category;

    const categoryIcons = Object.entries(SERVICE_MAPPINGS)
      .filter(([_, path]) => path.includes(currentCategory))
      .map(([name, path]) => ({
        path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
        name,
        category: currentCategory
      }));

    const selectedCategoryIcons = categoryIcons.length <= 4 ? 
      [...categoryIcons, ...categoryIcons.slice(0, 4 - categoryIcons.length)] : 
      categoryIcons.sort(() => 0.5 - Math.random()).slice(0, 4);

    selectedCategoryIcons.forEach(iconInfo => {
      let x = Math.floor(Math.random() * (canvasRef.current.width - 50));
      while (positions.some(pos => Math.abs(pos - x) < 50)) {
        x = Math.floor(Math.random() * (canvasRef.current.width - 50));
      }
      positions.push(x);

      const iconImage = new Image();
      iconImage.src = iconInfo.path;

      iconsRef.current.push({
        x,
        y: -50,
        type: iconInfo.category,
        name: iconInfo.name,
        image: iconImage,
        hit: false
      });
    });

    console.log(`New Mission: Shoot ${newInstructions[0].displayName} icons!`);
  };

  // Game initialization effect
  useEffect(() => {
    if (gameStarted && canvasRef.current) {
      canvasRef.current.width = 1200;
      canvasRef.current.height = 800;
      NewCategoryMission();
    }
  }, [gameStarted]);

  // Check if all icons are gone, then start a new category
  useEffect(() => {
    if (iconsRef.current.length === 0 && timeLeft > 0) {
      console.log("Icons depleted, loading new category...");
      NewCategoryMission();
    }
  }, [iconsRef.current]);

  return (
    <div className="gameCanvas-container">
      <h1 className="gameCanvas-game-title">AWS Cloud Shooter</h1>
      <canvas ref={canvasRef} className="gameCanvas-game-canvas" />

      <button onClick={() => setGameStarted(true)}>Start Game</button>

      {gameOver && (
        <div className="gameCanvas-game-over">
          <h3>Game Over!</h3>
          <button onClick={() => window.location.reload()}>Play Again</button>
        </div>
      )}
    </div>
  );
};

export default GameCanvas;
